SELECT course_id, COUNT(intake_id) AS intake_count
FROM intakes
GROUP BY course_id;

SELECT MIN(fee_amount) AS minimum_fee, MAX(fee_amount) AS maximum_fee
FROM course_fees
WHERE year = '2020';

SELECT course_id, fee_amount
FROM course_fees
WHERE fee_amount > 20000;

SELECT campus_name
FROM campuses
WHERE campus_id = 0;
